import{c as s,Q as n,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"FLP 不可能定理","description":"","frontmatter":{},"headers":[],"relativePath":"distributedLearning/09-FLP不可能定理.md","filePath":"distributedLearning/09-FLP不可能定理.md","lastUpdated":1778496697000}'),o={name:"distributedLearning/09-FLP不可能定理.md"};function p(i,a,l,r,c,u){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="flp-不可能定理" tabindex="-1">FLP 不可能定理 <a class="header-anchor" href="#flp-不可能定理" aria-label="Permalink to &quot;FLP 不可能定理&quot;">​</a></h1><p>1985 年 Fischer、Lynch、Paterson 写了一篇只有 9 页的论文,<strong>给&quot;分布式共识&quot;判了死刑</strong>——<em>&quot;Impossibility of Distributed Consensus with One Faulty Process&quot;</em>。结论是一句话:<strong>在纯异步网络里,只要有 1 个节点会 crash,就不存在一个总能在有限时间内达成共识的确定性算法</strong>。这听起来像「共识不可能」,但你天天用的 etcd、ZK、Spanner 全都在做共识——它们怎么活下来的?这一篇拆开 FLP,解释「<strong>FLP 不是&quot;共识不可能&quot;,是&quot;在某个理论模型下共识不可能&quot;</strong>」,Paxos / Raft 都是通过&quot;偷换前提&quot;绕开 FLP——<strong>这种&quot;偷换&quot;才是工程的精髓</strong>。</p><blockquote><p>一句话先记住:<strong>FLP = 异步 + 一个 crash + 确定性 ⇒ 没有总能 terminate 的共识算法</strong>。<strong>它没说共识不可能,只说在这四个前提下不可能</strong>——拿掉其中一个就有出路。<strong>工程上三条路:Dwork-Lynch-Stockmeyer 1988 的&quot;部分同步&quot;(Paxos/Raft 走这条);Ben-Or 1983 的&quot;随机化&quot;(BFT 共识用);Chandra-Toueg 1996 的&quot;失败检测器&quot;</strong>。<strong>Raft 的 election timeout 看起来朴素,本质上就是在偷换 FLP 的&quot;异步&quot;假设</strong>——它把异步偷换成&quot;部分同步&quot;,从而绕过定理。</p></blockquote><hr><h2 id="一、flp-在说什么-三句话讲清" tabindex="-1">一、FLP 在说什么:三句话讲清 <a class="header-anchor" href="#一、flp-在说什么-三句话讲清" aria-label="Permalink to &quot;一、FLP 在说什么:三句话讲清&quot;">​</a></h2><h3 id="_1-1-共识问题的最小定义" tabindex="-1">1.1 共识问题的最小定义 <a class="header-anchor" href="#_1-1-共识问题的最小定义" aria-label="Permalink to &quot;1.1 共识问题的最小定义&quot;">​</a></h3><p><strong>N 个节点,每个有一个初始值(0 或 1),要达成&quot;共识&quot;</strong>——意思是所有非故障节点最后都决定(decide)同一个值,且这个值是某个节点提议过的。</p><p><strong>正确的共识算法需要三条性质</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Agreement (一致性):所有正常节点 decide 同一个值</span></span>
<span class="line"><span>Validity   (有效性):decide 的值必须是某个节点提议过的(不能凭空捏造 42)</span></span>
<span class="line"><span>Termination(终止性):每个正常节点最终都会 decide(不能永远卡着)</span></span></code></pre></div><h3 id="_1-2-flp-的故障模型" tabindex="-1">1.2 FLP 的故障模型 <a class="header-anchor" href="#_1-2-flp-的故障模型" aria-label="Permalink to &quot;1.2 FLP 的故障模型&quot;">​</a></h3><p><strong>&quot;异步系统 + 至多 1 个 crash 故障&quot;</strong>:</p><ul><li><strong>异步</strong>:消息延迟没有上界(可以是 1ms,也可以是 1 小时,但终究会到)</li><li><strong>crash 故障</strong>:节点突然停止响应,不会发恶意消息(非拜占庭)</li><li><strong>确定性算法</strong>:同样输入同样输出,不依赖随机数</li></ul><h3 id="_1-3-flp-的结论" tabindex="-1">1.3 FLP 的结论 <a class="header-anchor" href="#_1-3-flp-的结论" aria-label="Permalink to &quot;1.3 FLP 的结论&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在异步系统 + 至多 1 个 crash + 确定性算法的前提下,</span></span>
<span class="line"><span>不存在一个共识协议能同时满足 Agreement + Validity + Termination。</span></span></code></pre></div><p><strong>通俗版</strong>:<strong>只要网络是纯异步的(没有超时机制),哪怕只有 1 台机器可能挂,你写不出一个共识算法保证总能在有限时间内拍板</strong>。</p><hr><h2 id="二、为什么这么反直觉-核心难点的直觉" tabindex="-1">二、为什么这么反直觉:核心难点的直觉 <a class="header-anchor" href="#二、为什么这么反直觉-核心难点的直觉" aria-label="Permalink to &quot;二、为什么这么反直觉:核心难点的直觉&quot;">​</a></h2><h3 id="_2-1-异步网络里你区分不了-挂了-vs-很慢" tabindex="-1">2.1 异步网络里你区分不了&quot;挂了&quot; vs &quot;很慢&quot; <a class="header-anchor" href="#_2-1-异步网络里你区分不了-挂了-vs-很慢" aria-label="Permalink to &quot;2.1 异步网络里你区分不了&quot;挂了&quot; vs &quot;很慢&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 A 给节点 B 发消息,等回复。</span></span>
<span class="line"><span>等了 5 秒还没回。B 是挂了还是网络拥塞?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>在同步网络:B 5 秒没回 = B 挂了(因为有&quot;消息一定 1 秒内到&quot;的保证)</span></span>
<span class="line"><span>在异步网络:B 5 秒没回 = 不知道</span></span>
<span class="line"><span>            消息可能还在路上,可能 10 秒后才到</span></span>
<span class="line"><span>            B 可能正在 GC,1 分钟后会回过神</span></span></code></pre></div><p><strong>如果 A 决定&quot;B 挂了&quot;就开始新一轮,但 B 其实活着——B 的旧消息后到,可能让协议状态不一致</strong>。</p><p><strong>如果 A 决定&quot;再等等&quot;,但 B 真的挂了——A 永远等下去</strong>。</p><blockquote><p><strong>这就是 FLP 的核心</strong>:<strong>异步网络里&quot;挂了&quot;和&quot;很慢&quot;在算法层面没有区别</strong>——任何确定性算法都可能被&quot;无限延迟&quot;卡死。</p></blockquote><h3 id="_2-2-bivalent-状态的构造-证明草图" tabindex="-1">2.2 Bivalent 状态的构造(证明草图) <a class="header-anchor" href="#_2-2-bivalent-状态的构造-证明草图" aria-label="Permalink to &quot;2.2 Bivalent 状态的构造(证明草图)&quot;">​</a></h3><p>FLP 论文用了一个精巧的归纳构造,<strong>核心概念是 bivalent 配置(双价配置)</strong>:</p><ul><li><strong>0-valent 配置</strong>:从这个全局状态出发,无论后续怎么走,最终一定 decide 0</li><li><strong>1-valent 配置</strong>:从这个全局状态出发,无论后续怎么走,最终一定 decide 1</li><li><strong>bivalent 配置(双价)</strong>:既可能走向 0,也可能走向 1(还没&quot;定型&quot;)</li></ul><p><strong>FLP 证明三步</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 初始配置中存在 bivalent 配置</span></span>
<span class="line"><span>   (如果某些节点初始值不同,系统启动时既可能 decide 0 也可能 decide 1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 任何 bivalent 配置都存在一条&quot;特定的消息延迟序列&quot;,</span></span>
<span class="line"><span>   能让系统永远保持 bivalent —— 永远没&quot;定型&quot;</span></span>
<span class="line"><span>   (用 1 个 crash 故障 + 调度器无限拖延某条关键消息来构造)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 因此存在一条无限执行路径,系统永远不 decide</span></span>
<span class="line"><span>   → 违反 Termination</span></span></code></pre></div><p><strong>通俗说</strong>:<strong>对抗性的&quot;网络调度者&quot;总能挑选一条消息延迟序列,让系统在&quot;该 0 还是该 1&quot;之间反复横跳</strong>——只要还有 1 个节点可能 crash,调度者就有足够的&quot;延迟自由度&quot;维持这种 ambivalence。</p><blockquote><p><strong>这不是一个具体算法的失败,是对所有可能算法的失败</strong>——任何你能写出来的确定性共识协议,都能被这个对抗调度构造击败。</p></blockquote><hr><h2 id="三、flp-三角-四要素必须舍一" tabindex="-1">三、FLP 三角:四要素必须舍一 <a class="header-anchor" href="#三、flp-三角-四要素必须舍一" aria-label="Permalink to &quot;三、FLP 三角:四要素必须舍一&quot;">​</a></h2><p>把 FLP 重新表述成&quot;四选三&quot;:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>            异步(Async)</span></span>
<span class="line"><span>              ╱  ╲</span></span>
<span class="line"><span>             ╱    ╲</span></span>
<span class="line"><span>            ╱      ╲</span></span>
<span class="line"><span>   故障(Fault)──共识(Safety+Liveness)</span></span>
<span class="line"><span>            ╲      ╱</span></span>
<span class="line"><span>             ╲    ╱</span></span>
<span class="line"><span>              ╲  ╱</span></span>
<span class="line"><span>          确定性(Deterministic)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要 Agreement(Safety) + Termination(Liveness),</span></span>
<span class="line"><span>+ Async + 1 crash + Deterministic = 不可能(FLP)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>舍一才能解:</span></span>
<span class="line"><span>舍 Async        → 部分同步(Paxos / Raft)</span></span>
<span class="line"><span>舍 Fault        → 假设 0 个 crash(没意义)</span></span>
<span class="line"><span>舍 Deterministic → 随机化(Ben-Or)</span></span>
<span class="line"><span>舍 Liveness 偏弱  → 接受&quot;可能永远不 terminate,但 safety 永远不破&quot;</span></span></code></pre></div><h3 id="_3-1-safety-永远-liveness-是工程信条" tabindex="-1">3.1 &quot;Safety 永远 &gt; Liveness&quot; 是工程信条 <a class="header-anchor" href="#_3-1-safety-永远-liveness-是工程信条" aria-label="Permalink to &quot;3.1 &quot;Safety 永远 &gt; Liveness&quot; 是工程信条&quot;">​</a></h3><p><strong>Raft 论文里有句名言</strong>:</p><blockquote><p><em>&quot;It is OK to be unavailable, but never inconsistent.&quot;</em></p></blockquote><p>对应到 FLP——<strong>所有真实共识算法都保证 Safety(Agreement + Validity)永远不破,但允许 Liveness 在极端情况下暂时挂掉</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Raft 在 split-brain 间隙没法选出 Leader → 短暂不可用,但绝不会两个 Leader 同时提交</span></span>
<span class="line"><span>Paxos 在两个 Proposer &quot;互相抢&quot; 时可能反复打架 → 短暂不前进,但绝不会两个值都被 chosen</span></span></code></pre></div><p><strong>FLP 没法让你&quot;既快又对&quot;——工程接受&quot;偶尔慢一会,但永远对&quot;</strong>。</p><hr><h2 id="四、出路一-部分同步-dwork-lynch-stockmeyer-1988" tabindex="-1">四、出路一:部分同步(Dwork-Lynch-Stockmeyer 1988) <a class="header-anchor" href="#四、出路一-部分同步-dwork-lynch-stockmeyer-1988" aria-label="Permalink to &quot;四、出路一:部分同步(Dwork-Lynch-Stockmeyer 1988)&quot;">​</a></h2><p><strong>Paxos / Raft / ZAB 全都靠这条出路</strong>。</p><h3 id="_4-1-部分同步模型" tabindex="-1">4.1 部分同步模型 <a class="header-anchor" href="#_4-1-部分同步模型" aria-label="Permalink to &quot;4.1 部分同步模型&quot;">​</a></h3><p>DLS 1988 论文提出三种网络模型:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Synchronous      消息延迟有已知上界 Δ —— 不现实(网络总会抖)</span></span>
<span class="line"><span>Asynchronous     延迟无上界 —— FLP 死刑</span></span>
<span class="line"><span>Partially Sync   延迟最终有上界 Δ,但 Δ 未知,或者只在某个&quot;未知时刻 GST&quot;之后才生效</span></span>
<span class="line"><span>                 GST = Global Stabilization Time(全局稳定时间)</span></span></code></pre></div><p><strong>部分同步的本质</strong>:</p><blockquote><p><strong>网络可以任意抖,但总会有&quot;安静下来&quot;的时段</strong>——只要在那个时段里能选出 Leader、完成一轮共识,Liveness 就保住了。</p></blockquote><h3 id="_4-2-paxos-raft-怎么用部分同步" tabindex="-1">4.2 Paxos / Raft 怎么用部分同步 <a class="header-anchor" href="#_4-2-paxos-raft-怎么用部分同步" aria-label="Permalink to &quot;4.2 Paxos / Raft 怎么用部分同步&quot;">​</a></h3><p><strong>Raft 的 election timeout(默认 150-300ms 随机)就是部分同步假设的实现</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Follower 在 election timeout 内没收到 Leader 心跳 → &quot;假设 Leader 挂了&quot;</span></span>
<span class="line"><span>2. 自荐 Candidate,发 RequestVote</span></span>
<span class="line"><span>3. 收到多数派票 → 成为 Leader</span></span>
<span class="line"><span>4. 如果没收到多数派(同时有多个 Candidate)→ 等下一轮随机 timeout 重试</span></span></code></pre></div><p><strong>关键玩法</strong>:<strong>随机化 timeout</strong>——让两个 Candidate &quot;撞车&quot;的概率小,加上一旦撞车下一轮 timeout 不同,<strong>最终一定有人单独 timeout 先</strong>。</p><p><strong>这能绕过 FLP 吗?</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FLP 说:对手能构造一条延迟序列让算法永不 terminate</span></span>
<span class="line"><span>Raft 说:对手可以 — 但只要在某个 GST 之后网络稳定 Δ ms,</span></span>
<span class="line"><span>        某个节点的 election timeout 一定会触发,</span></span>
<span class="line"><span>        而且其他节点的票一定能在 Δ 内到达,</span></span>
<span class="line"><span>        所以选主一定能完成。</span></span></code></pre></div><p><strong>Raft 偷换的就是&quot;异步&quot;假设</strong>——它假设&quot;虽然不知道 Δ 多大,但 Δ 总是会有&quot;。<strong>这个假设在真实数据中心 99.99% 时间成立</strong>。</p><h3 id="_4-3-不成立时会发生什么" tabindex="-1">4.3 不成立时会发生什么? <a class="header-anchor" href="#_4-3-不成立时会发生什么" aria-label="Permalink to &quot;4.3 不成立时会发生什么?&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>极端 case:某个数据中心持续 30 分钟全程网络抖动,每 100ms 抖一下</span></span>
<span class="line"><span>→ Raft 选主反复失败(每个 Candidate 都在 timeout 前被新心跳打断)</span></span>
<span class="line"><span>→ Liveness 挂了,集群无 Leader,所有写阻塞</span></span>
<span class="line"><span>→ 但 Safety 保留(没有任何写被错误 commit)</span></span></code></pre></div><p><strong>真实事故</strong>:<strong>etcd 在某些云上抖动严重的场景出现过持续几分钟无 Leader</strong>——这是 FLP 在工程里&quot;露脸&quot;的时刻。</p><hr><h2 id="五、出路二-随机化-ben-or-1983" tabindex="-1">五、出路二:随机化(Ben-Or 1983) <a class="header-anchor" href="#五、出路二-随机化-ben-or-1983" aria-label="Permalink to &quot;五、出路二:随机化(Ben-Or 1983)&quot;">​</a></h2><p><strong>第二条路:放弃确定性</strong>。</p><h3 id="_5-1-ben-or-算法直觉" tabindex="-1">5.1 Ben-Or 算法直觉 <a class="header-anchor" href="#_5-1-ben-or-算法直觉" aria-label="Permalink to &quot;5.1 Ben-Or 算法直觉&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每轮:</span></span>
<span class="line"><span>  1. 节点发自己当前值给所有人</span></span>
<span class="line"><span>  2. 收 N-f 个回复(f 是允许故障数)</span></span>
<span class="line"><span>  3. 如果多数派一致 → decide</span></span>
<span class="line"><span>  4. 否则 → 随机抛硬币选 0 或 1,作下一轮初值</span></span>
<span class="line"><span>  5. goto 1</span></span></code></pre></div><p><strong>为什么能绕过 FLP</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FLP 假设算法是确定性的 — 对手知道算法,能精确构造延迟攻击</span></span>
<span class="line"><span>Ben-Or 引入随机 — 对手不知道下一轮硬币结果</span></span>
<span class="line"><span>        → 不能精准让系统永远 bivalent</span></span>
<span class="line"><span>        → 系统以&quot;接近 1 的概率&quot;在有限轮收敛(期望终止 O(2^N) 轮)</span></span></code></pre></div><p><strong>注意</strong>:<strong>Ben-Or 只保证 probabilistic termination</strong>(概率上终止)——可能永远不终止但概率为 0。</p><h3 id="_5-2-工程影响" tabindex="-1">5.2 工程影响 <a class="header-anchor" href="#_5-2-工程影响" aria-label="Permalink to &quot;5.2 工程影响&quot;">​</a></h3><p><strong>Ben-Or 在拜占庭共识(15 篇)里有变种</strong>:HoneyBadgerBFT、Algorand 都用了&quot;密码学随机数 + Ben-Or 思路&quot;实现拜占庭+异步共识——<strong>这是 FLP 在拜占庭场景的标准绕过法</strong>。</p><p><strong>Paxos / Raft 不用随机化绕 FLP</strong>(它们走部分同步路线),<strong>但 Raft 的随机 election timeout 是借鉴随机化思想缩短选主延迟</strong>——本质不是绕过 FLP,只是缓解 split vote。</p><hr><h2 id="六、出路三-失败检测器-chandra-toueg-1996" tabindex="-1">六、出路三:失败检测器(Chandra-Toueg 1996) <a class="header-anchor" href="#六、出路三-失败检测器-chandra-toueg-1996" aria-label="Permalink to &quot;六、出路三:失败检测器(Chandra-Toueg 1996)&quot;">​</a></h2><p><strong>第三条路:不强求异步,引入一个&quot;oracle&quot;告诉你谁挂了</strong>。</p><h3 id="_6-1-失败检测器是什么" tabindex="-1">6.1 失败检测器是什么 <a class="header-anchor" href="#_6-1-失败检测器是什么" aria-label="Permalink to &quot;6.1 失败检测器是什么&quot;">​</a></h3><p><strong>抽象一个外部模块 FD</strong>,负责回答&quot;节点 X 是否故障?&quot;——<strong>有不同强度</strong>:</p><table tabindex="0"><thead><tr><th>级别</th><th>完整性</th><th>准确性</th><th>实现方式</th></tr></thead><tbody><tr><td>P (Perfect)</td><td>所有故障都被检测</td><td>不误判活节点</td><td>需要同步网络,工程难做</td></tr><tr><td>S (Strong)</td><td>所有故障都被最终检测</td><td>最终不误判</td><td>部分同步可实现</td></tr><tr><td>◇S (Eventually Strong)</td><td>最终所有故障被检测</td><td>最终不误判</td><td><strong>工程的标配</strong></td></tr></tbody></table><h3 id="_6-2-chandra-toueg-的关键结论" tabindex="-1">6.2 Chandra-Toueg 的关键结论 <a class="header-anchor" href="#_6-2-chandra-toueg-的关键结论" aria-label="Permalink to &quot;6.2 Chandra-Toueg 的关键结论&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有 ◇S 失败检测器 + 多数派正常 ⇒ 可以做共识(异步网络)</span></span></code></pre></div><p><strong>这等价于偷换了&quot;异步&quot;</strong>——你说网络异步,我说我有外部 oracle 能&quot;告诉我谁挂了&quot;,于是 FLP 不再适用。</p><p><strong>工程上 ◇S 的实现就是&quot;心跳 + timeout&quot;</strong>——和 Raft 的 leader heartbeat 几乎一样。<strong>所以 Chandra-Toueg 和 DLS 1988 在工程上是同一条路的两种说法</strong>。</p><h3 id="_6-3-φ-accrual-失败检测器-cassandra-akka" tabindex="-1">6.3 φ-accrual 失败检测器(Cassandra / Akka) <a class="header-anchor" href="#_6-3-φ-accrual-失败检测器-cassandra-akka" aria-label="Permalink to &quot;6.3 φ-accrual 失败检测器(Cassandra / Akka)&quot;">​</a></h3><p><strong>真实工程里&quot;心跳 + 阈值 timeout&quot; 太硬,Cassandra/Akka 用 φ-accrual</strong>:</p><ul><li>不给&quot;挂没挂&quot;的二值答案,<strong>给一个数 φ</strong></li><li>φ 越大,&quot;挂了&quot;的可能性越高</li><li>阈值由应用层选(φ &gt; 8 ≈ 1/10000 概率误判)</li></ul><p><strong>这是失败检测器的工程精细化</strong>,详见 30 篇故障检测。</p><hr><h2 id="七、paxos-raft-是怎么-踩着-flp-工作的" tabindex="-1">七、Paxos / Raft 是怎么&quot;踩着 FLP&quot; 工作的 <a class="header-anchor" href="#七、paxos-raft-是怎么-踩着-flp-工作的" aria-label="Permalink to &quot;七、Paxos / Raft 是怎么&quot;踩着 FLP&quot; 工作的&quot;">​</a></h2><p>回到工程,<strong>Paxos 和 Raft 的设计可以这么理解</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paxos / Raft 的 Safety:任何情况下都不会出现&quot;两个不同值都被 commit&quot;</span></span>
<span class="line"><span>Paxos / Raft 的 Liveness:在&quot;网络最终稳定 + 多数派活着&quot; 的条件下,共识在有限时间内达成</span></span>
<span class="line"><span></span></span>
<span class="line"><span>——这就是 FLP 三选三的妥协:</span></span>
<span class="line"><span>  ✓ Agreement</span></span>
<span class="line"><span>  ✓ Validity</span></span>
<span class="line"><span>  ◇ Termination(只在部分同步时刻,不是无条件)</span></span></code></pre></div><h3 id="_7-1-raft-几条-flp-反例" tabindex="-1">7.1 Raft 几条&quot;FLP 反例&quot; <a class="header-anchor" href="#_7-1-raft-几条-flp-反例" aria-label="Permalink to &quot;7.1 Raft 几条&quot;FLP 反例&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>反例 1:无限选主循环</span></span>
<span class="line"><span>  五个节点同时 election timeout → 互相投自己 → 没人拿多数票 → 下一轮</span></span>
<span class="line"><span>  理论上 FLP 允许这个循环永远不停</span></span>
<span class="line"><span>  Raft 的对策:随机 timeout → &quot;撞车&quot; 概率小,期望几轮就有一个先出来</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反例 2:网络持续抖动</span></span>
<span class="line"><span>  Leader 心跳总是 timeout 边缘到达 → Follower 反复重选</span></span>
<span class="line"><span>  Raft 不能完全解决 → 这是&quot;部分同步&quot; 假设不成立的代价</span></span>
<span class="line"><span>  工程对策:调大 election timeout(从 150ms 调到 1s),牺牲故障切换速度换稳定</span></span>
<span class="line"><span></span></span>
<span class="line"><span>反例 3:对称故障</span></span>
<span class="line"><span>  五节点,网络分成 2+2+1 三组,任何一组都没多数 → 任何一边都选不出 Leader</span></span>
<span class="line"><span>  Raft 直接 Liveness 挂 → 等网络合并</span></span>
<span class="line"><span>  Safety 保留 → 不会写出冲突数据</span></span></code></pre></div><h3 id="_7-2-multi-paxos-的类似妥协" tabindex="-1">7.2 Multi-Paxos 的类似妥协 <a class="header-anchor" href="#_7-2-multi-paxos-的类似妥协" aria-label="Permalink to &quot;7.2 Multi-Paxos 的类似妥协&quot;">​</a></h3><p>Multi-Paxos 用&quot;distinguished proposer&quot;(就是 Leader)避免反复打架,<strong>但选 Leader 的过程本身仍可能在异步抖动下卡死</strong>——和 Raft 一回事。</p><p><strong>结论</strong>:<strong>Paxos / Raft 都&quot;基本接受了 FLP 的存在,但用工程化的部分同步把它压到 99.99% 不发生&quot;</strong>——这就是工程的胜利。</p><hr><h2 id="八、flp-vs-cap-同一种-不可能-的两种表达" tabindex="-1">八、FLP vs CAP:同一种&quot;不可能&quot;的两种表达 <a class="header-anchor" href="#八、flp-vs-cap-同一种-不可能-的两种表达" aria-label="Permalink to &quot;八、FLP vs CAP:同一种&quot;不可能&quot;的两种表达&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FLP:异步 + 1 crash + 确定性 ⇒ 不存在总能 terminate 的共识</span></span>
<span class="line"><span>CAP:网络分区时,C 和 A 二选一</span></span>
<span class="line"><span></span></span>
<span class="line"><span>关系:CAP 是 FLP 在&quot;分区故障&quot;场景下的特例</span></span>
<span class="line"><span>  分区 = 一组节点间消息延迟变无穷大 = 异步极端化</span></span>
<span class="line"><span>  在分区下要做 C,等价于要做共识 → FLP 适用 → 不可能同时保 A(Liveness)</span></span></code></pre></div><p><strong>更精细的对应</strong>:</p><table tabindex="0"><thead><tr><th>FLP</th><th>CAP</th></tr></thead><tbody><tr><td>异步(消息延迟无上界)</td><td>分区(子集间消息丢失)</td></tr><tr><td>Termination</td><td>Availability</td></tr><tr><td>Agreement</td><td>Consistency</td></tr><tr><td>部分同步出路</td><td>分区恢复后重新可用</td></tr></tbody></table><p><strong>所以 CAP 不是独立的定理,是 FLP 的工程化叙事</strong>——Brewer 2000 提的时候没引用 FLP,但本质上同一个东西。</p><h3 id="_8-1-flp-比-cap-贵" tabindex="-1">8.1 FLP 比 CAP &quot;贵&quot; <a class="header-anchor" href="#_8-1-flp-比-cap-贵" aria-label="Permalink to &quot;8.1 FLP 比 CAP &quot;贵&quot;&quot;">​</a></h3><p>FLP 的可怕之处:<strong>不需要分区就生效</strong>——<strong>只要 1 个节点 crash + 异步网络,共识就可能卡死</strong>。CAP 至少要等到分区发生才&quot;二选一&quot;,<strong>FLP 在网络稍微一抖就开始要命</strong>。</p><hr><h2 id="九、flp-的工程实战意义" tabindex="-1">九、FLP 的工程实战意义 <a class="header-anchor" href="#九、flp-的工程实战意义" aria-label="Permalink to &quot;九、FLP 的工程实战意义&quot;">​</a></h2><h3 id="_9-1-设计共识协议时" tabindex="-1">9.1 设计共识协议时 <a class="header-anchor" href="#_9-1-设计共识协议时" aria-label="Permalink to &quot;9.1 设计共识协议时&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 先证明 Safety(invariant 永远成立)</span></span>
<span class="line"><span>2. 再说明 Liveness 在哪些假设下成立</span></span>
<span class="line"><span>3. 明确写出&quot;Liveness 不保证&quot;的边界条件(网络抖动模式、故障数)</span></span></code></pre></div><p><strong>Raft 论文 §5.4 专门论证 Safety</strong>——这是 FLP 教给我们的纪律。</p><h3 id="_9-2-配置共识系统时" tabindex="-1">9.2 配置共识系统时 <a class="header-anchor" href="#_9-2-配置共识系统时" aria-label="Permalink to &quot;9.2 配置共识系统时&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>election_timeout:太小 → 误判 Leader 死(违反&quot;部分同步&quot;假设)</span></span>
<span class="line"><span>                  太大 → 真挂了切主慢,影响 Liveness</span></span>
<span class="line"><span>                  推荐 ≥ 10 × 网络平均 RTT,留足抖动空间</span></span>
<span class="line"><span></span></span>
<span class="line"><span>heartbeat_interval:&lt; election_timeout / 3</span></span>
<span class="line"><span>                   保证心跳 miss 一两个不会误触发选主</span></span></code></pre></div><p><strong>这些参数的本质是在调&quot;部分同步&quot;假设的强度</strong>——你越保守,Safety 越稳但故障切换越慢。</p><h3 id="_9-3-排查-liveness-挂了" tabindex="-1">9.3 排查&quot;Liveness 挂了&quot; <a class="header-anchor" href="#_9-3-排查-liveness-挂了" aria-label="Permalink to &quot;9.3 排查&quot;Liveness 挂了&quot;&quot;">​</a></h3><p><strong>生产事故的诊断顺序</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 是不是网络持续抖动?(部分同步假设不成立)</span></span>
<span class="line"><span>2. 是不是少数派活着?(多数派全挂,共识算法不可能继续)</span></span>
<span class="line"><span>3. 是不是时钟偏差超 max_offset?(HLC/Raft 的隐式假设)</span></span>
<span class="line"><span>4. 是不是 GC 暂停 &gt; election_timeout?(误判节点挂)</span></span></code></pre></div><p><strong>95% 的 Raft 集群&quot;卡死&quot;事故都能归到这四类——本质都是工程假设不成立</strong>。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为&quot;FLP 说共识不可能&quot;</strong>——它说的是&quot;在异步 + 1 crash + 确定性下不可能&quot;,<strong>改任何一个前提就有出路</strong>。<strong>别用这个唬人,你天天用的 etcd 就在做共识</strong>。</li><li><strong>以为&quot;加超时就能 100% 解决 FLP&quot;</strong>——超时只是&quot;部分同步&quot;的工程实现,<strong>网络持续抖动时 Raft 也会 Liveness 挂</strong>。FLP 在某些极端工况下仍会露脸。</li><li><strong>追求&quot;Liveness 永远不挂&quot;</strong>——办不到。<strong>接受&quot;宁可暂时不可用,绝不破坏一致性&quot;</strong>——这是 Raft 论文的工程哲学。</li><li><strong>election_timeout 配太小</strong>——150ms 在跨机房抖动场景下会反复选主,<strong>Liveness 严重退化</strong>。跨机房至少 1s。</li><li><strong>以为随机化能&quot;绕过&quot;FLP</strong>——Ben-Or 只是 probabilistic termination,<strong>期望终止时间 O(2^N) 节点多了根本不能用</strong>。生产共识不靠纯随机化。</li><li><strong>拿 FLP 否定 Paxos / Raft</strong>——FLP 的&quot;不可能&quot;和工程的&quot;几乎总能&quot; 不矛盾。<strong>FLP 是理论 lower bound,Paxos / Raft 是在 99.99% 工况下的工程 upper bound</strong>。</li><li><strong>混淆 Safety 和 Liveness 故障</strong>——Safety 故障(双 Leader / 双 commit)是数据损坏,<strong>必须修代码</strong>;Liveness 故障(无 Leader / 卡选主)是可用性问题,<strong>调参数 / 加节点</strong>。两者根本不是一回事。</li><li><strong>以为&quot;网络分区 = FLP 场景&quot;</strong>——分区只是 FLP 异步的极端情况,<strong>FLP 在&quot;网络正常但抖动&quot;时就生效了</strong>——所以共识系统在小抖动下也会偶发 Liveness 失败。</li><li><strong>拿 FLP 反对&quot;全异步设计&quot;</strong>——异步通信和异步系统模型不是一回事,<strong>RabbitMQ 异步消息不等于 FLP 的&quot;异步网络&quot;</strong>;FLP 针对的是&quot;延迟无上界&quot;,生产网络抖动有上界(虽然抖)。</li><li><strong>不理解&quot;FLP 不可能&quot; ≠ &quot;做不出来&quot;</strong>——做出来的关键是<strong>加假设</strong>。<strong>Raft 加&quot;部分同步&quot;;Spanner 加&quot;原子钟&quot;(等于加&quot;时间近似同步&quot;);PBFT 加&quot;3f+1 多数派&quot;(等于强化故障假设)</strong>——每个真实系统都在偷换前提。<strong>学共识就是学&quot;每个算法到底偷换了哪个 FLP 前提&quot;</strong>。</li></ol><hr><p>下一篇 <code>10-复制三态</code>:FLP 告诉我们共识贵,**那大多数业务能不能&quot;少做点共识&quot;?**主从复制、多主复制、无主复制 + Quorum NWR——<strong>复制是共识的&quot;穷人版&quot;</strong>,大多数业务用不到 Paxos / Raft,<strong>只需要选对一种复制策略</strong>。下一篇拆开三种复制模式各自的不变量、代价、典型系统(MySQL / Redis / Cassandra / DynamoDB)。</p>`,116)])])}const g=s(o,[["render",p]]);export{h as __pageData,g as default};
